import * as React from "react";
import Layout from "../components/Layout";
import { Box, Link, Heading, BaseStyles, Divider } from "theme-ui";
import { Link as GatsbyLink, graphql } from "gatsby";
import {
  groupByTimeWithRepo,
  getInfoById,
  getDateString,
  getManualDateString,
  getPageType,
} from "../utils";
import DateDoc from "../components/DateDoc";
import FooterNav from "../components/FooterNav";
import HomeNav from "../components/HomeNav";
import SEO from "../components/seo";
// markup
const IndexPage = ({ location, data, pageContext }) => {
  const items = data.allAwesomeItem.nodes;
  const type = pageContext.type || "day";
  const groups = groupByTimeWithRepo(items, type);

  let previousInfo = null;
  if (pageContext.previousId) {
    previousInfo = getInfoById(
      pageContext.previousId,
      pageContext.previousName
    );
  }
  let nextInfo = null;
  if (pageContext.nextId) {
    nextInfo = getInfoById(pageContext.nextId, pageContext.nextName);
  }
  let title = "Home";
  if (type === "homeWeek") {
    title = "Track your Favorite Github Awesome Repo Weekly";
  } else if (type === "week" || type === "day") {
    title = getManualDateString(groups[0].updatedAt, type);
  } else {
    title = "Track your Favorite Github Awesome Repo";
  }
  return (
    <Layout location={location}>
      <SEO title={title} />
      <Box p="default" sx={{ maxWidth: "5xl" }}>
        <HomeNav location={location}></HomeNav>
        <Box>
          {groups &&
            groups.length > 0 &&
            groups.map((rootGroup, index) => {
              return (
                <Box key={`root-group-${index}`}>
                  <Link as={GatsbyLink} variant="none" to={rootGroup.slug}>
                    <Heading as="h2" pb="sm">
                      {getDateString(rootGroup.updatedAt, type)}
                    </Heading>
                  </Link>

                  <Box variant="docs.date">
                    {rootGroup.groups.map((group, index) => {
                      group.index = index;
                      return (
                        <DateDoc
                          key={`grouped-by-repo-${group.awesomeListRepo}`}
                          group={group}
                        ></DateDoc>
                      );
                    })}
                  </Box>
                </Box>
              );
            })}
        </Box>
        <FooterNav previous={previousInfo} next={nextInfo}></FooterNav>
      </Box>
    </Layout>
  );
};

export default IndexPage;
export const pageQuery = graphql`
  query awesomeIndex($from: Float!, $to: Float!) {
    site {
      siteMetadata {
        title
      }
    }
    allAwesomeItem(
      filter: { updateTime: { gte: $from, lte: $to } }
      sort: { fields: updateTime, order: DESC }
    ) {
      nodes {
        awesomeListRepo
        categoryHTML
        itemHTML
        updatedAt
      }
    }
  }
`;
