import * as React from "react";
import {
  Box,
  NavLink,
  Button,
  Heading,
  Flex,
  Link,
  BaseStyles,
  Text,
} from "theme-ui";
import { Link as GatsbyLink } from "gatsby";
import { useOverlayTriggerState } from "@react-stately/overlays";
import { SUBSCRIBE_TITLE } from "../config";
import { External, RSS, Email, Twitter, Telegram } from "./Icons";
import { getPageType } from "../utils";
import Subscribe from "./Subscribe";
import Modal from "./Modal";
export default function ({ meta, location }) {
  const pageType = getPageType(location.pathname);
  const rssHref =
    pageType === "week" || pageType === "homeWeek"
      ? `/week/rss.xml`
      : `/rss.xml`;
  let state = useOverlayTriggerState({});

  return (
    <Box>
      {state.isOpen && (
        <Modal title={SUBSCRIBE_TITLE} onClose={state.close}>
          <Subscribe onClose={state.close}></Subscribe>
        </Modal>
      )}
      <Flex
        pb="30px"
        sx={{
          fontSize: 2,
          justifyContent: "space-between",
          flexWrap: "wrap",
        }}
      >
        <Box pb="1">
          <Text>View by</Text>
          <NavLink
            as={GatsbyLink}
            variant={
              pageType === "day" || pageType === "home" ? "navActive" : "nav"
            }
            to={`/`}
          >
            DAY
          </NavLink>
          /
          <NavLink
            as={GatsbyLink}
            variant={
              pageType === "week" || pageType === "homeWeek"
                ? "navActive"
                : "nav"
            }
            to={`/week`}
          >
            WEEK
          </NavLink>
        </Box>
        <Box pb="1">
          <Link
            title="Twitter"
            target="_blank"
            rel="noopener noreferrer"
            href="https://twitter.com/trackawesome"
            mr="sm"
            variant="external"
          >
            <Twitter></Twitter>
          </Link>
          <Link
            title="Telegram"
            target="_blank"
            rel="noopener noreferrer"
            href="https://t.me/trackawesomelist"
            mr="sm"
            variant="external"
          >
            <Telegram></Telegram>
          </Link>
          <Link
            title="RSS"
            target="_blank"
            rel="noopener noreferrer"
            href={rssHref}
            mr="sm"
            variant="external"
          >
            <RSS></RSS>
          </Link>
          <Button title="Email" onClick={state.open} mr="sm" variant="textLink">
            Subscribe
            <span style={{ marginLeft: "6px" }}>
              <Email></Email>
            </span>
          </Button>
        </Box>
      </Flex>
    </Box>
  );
}
